/* praise-audio.js -- positive-affirmation clips for ColorMyMath
 *
 * Loaded after audio-library.js.  Registers every clip with AudioLib
 * under a "praise_*" key and exposes window.playRandomPraise() which
 * picks one at random and plays it through the shared audio engine.
 *
 * The clips were recorded as one-off WAVs, trimmed to remove leading
 * and trailing silence, then base64-encoded into this file so no extra
 * network requests are needed.
 */
(function () {
  if (!window.AudioLib) return;
  var PRAISE_CLIPS = {
    "praise_great_answer": "data:audio/wav;base64,",
    "praise_thats_correct": "data:audio/wav;base64,",
    "praise_keep_pushing": "data:audio/wav;base64,",
    "praise_nice_progress": "data:audio/wav;base64,",
    "praise_excellent_work": "data:audio/wav;base64,",
    "praise_you_are_clever": "data:audio/wav;base64,",
    "praise_very_good": "data:audio/wav;base64,",
    "praise_thats_the_way": "data:audio/wav;base64,",
    "praise_keep_it_up": "data:audio/wav;base64,",
    "praise_you_did_it": "data:audio/wav;base64,",
    "praise_impressive": "data:audio/wav;base64,",
    "praise_strong_work": "data:audio/wav;base64,",
    "praise_good_thinking": "data:audio/wav;base64,",
    "praise_you_are_smart": "data:audio/wav;base64,",
    "praise_just_like_that": "data:audio/wav;base64,",
    "praise_great_effort": "data:audio/wav;base64,",
    "praise_good_effort": "data:audio/wav;base64,",
    "praise_thats_it": "data:audio/wav;base64,",
    "praise_youre_doing_great": "data:audio/wav;base64,",
    "praise_nice_work": "data:audio/wav;base64,",
    "praise_right_on": "data:audio/wav;base64,",
    "praise_yes": "data:audio/wav;base64,",
    "praise_you_got_it": "data:audio/wav;base64,",
    "praise_well_done": "data:audio/wav;base64,",
    "praise_bravo": "data:audio/wav;base64,",
    "praise_splendid": "data:audio/wav;base64,",
    "praise_marvelous": "data:audio/wav;base64,",
    "praise_outstanding": "data:audio/wav;base64,",
    "praise_amazing": "data:audio/wav;base64,",
    "praise_brilliant": "data:audio/wav;base64,",
    "praise_fantastic": "data:audio/wav;base64,",
    "praise_wonderful": "data:audio/wav;base64,",
    "praise_super": "data:audio/wav;base64,",
    "praise_great": "data:audio/wav;base64,",
    "praise_awesome": "data:audio/wav;base64,",
    "praise_fabulous": "data:audio/wav;base64,",
    "praise_excellent": "data:audio/wav;base64,",
    "praise_nice": "data:audio/wav;base64,",
    "praise_thats_right": "data:audio/wav;base64,",
    "praise_way_to_go": "data:audio/wav;base64,",
    "praise_good_job": "data:audio/wav;base64,",
    "praise_terrific": "data:audio/wav;base64,",
  };
  window.PRAISE_KEYS = Object.keys(PRAISE_CLIPS);
  // Fire-and-forget bulk register; the keys are usable once the buffers
  // decode (a few hundred ms).  AudioLib.play silently no-ops if a key
  // isn't decoded yet, so first-tap praise just falls back gracefully.
  AudioLib.registerClips(PRAISE_CLIPS);

  // Cycle through the praise pool in a freshly-shuffled order each pass
  // so the kid hears every clip once before any repeats.
  var _bag = [];
  function _refillBag() {
    _bag = window.PRAISE_KEYS.slice();
    for (var i = _bag.length - 1; i > 0; i--) {
      var j = Math.floor(Math.random() * (i + 1));
      var t = _bag[i]; _bag[i] = _bag[j]; _bag[j] = t;
    }
  }
  window.playRandomPraise = function () {
    if (!_bag.length) _refillBag();
    var key = _bag.pop();
    try { AudioLib.play(key); } catch (e) {}
  };
})();
